def perceive(data):
    if isinstance(data, dict):
        value = data.get("cloud_cover")
    else:
        text = str(data)
        value = None
        for part in text.replace(",", "\n").splitlines():
            if "cloud_cover" in part and ":" in part:
                value = part.split(":", 1)[1].strip()
        if value is None:
            value = text.strip()
    try:
        value = float(value)
    except (TypeError, ValueError):
        return {}
    value = min(1.0, max(0.0, value))
    return {"cloud_cover": value}
